// src/Dashboard.js
import React, { useEffect, useState } from "react";

const apiBase = "https://prasa-backend-1.onrender.com";
const green = "#0f9d58";
const lightGreen = "#eaf8f0";
const white = "#ffffff";

function Dashboard({ employee, onLogout }) {
  const [travelCount, setTravelCount] = useState(0);
  const [ticketCount, setTicketCount] = useState(0);
  const [message, setMessage] = useState("");

  useEffect(() => {
    if (employee?.empld) {
      loadCounts();
    }
  }, [employee]);

  const loadCounts = async () => {
    try {
      setMessage("Loading summary...");
      const [tRes, kRes] = await Promise.all([
        fetch(`${apiBase}/travel-expenses?empld=${encodeURIComponent(employee.empld)}`),
        fetch(`${apiBase}/ticket-expenses?empld=${encodeURIComponent(employee.empld)}`),
      ]);

      const [travel, tickets] = await Promise.all([tRes.json(), kRes.json()]);
      setTravelCount(travel?.length || 0);
      setTicketCount(tickets?.length || 0);
      setMessage("");
    } catch (err) {
      console.error("Dashboard summary error:", err);
      setMessage("❌ Could not load summary.");
    }
  };

  return (
    <div
      style={{
        fontFamily: "Segoe UI",
        background: lightGreen,
        minHeight: "100vh",
        padding: 20,
      }}
    >
      <div
        style={{
          maxWidth: 900,
          margin: "0 auto",
          background: white,
          borderRadius: 14,
          boxShadow: "0 6px 20px rgba(0,0,0,0.12)",
          overflow: "hidden",
        }}
      >
        {/* Header */}
        <header
          style={{
            padding: 16,
            background: green,
            color: white,
            display: "flex",
            justifyContent: "space-between",
            alignItems: "center",
            flexWrap: "wrap",
            gap: 8,
          }}
        >
          <div>
            <div style={{ fontSize: 18, fontWeight: 700 }}>
              PRASA Employee Dashboard
            </div>
            <div style={{ marginTop: 4, fontSize: 13 }}>
              {employee.name} • {employee.empld} — {employee.department} (
              {employee.role || "Employee"})
            </div>
          </div>

          <button
            onClick={onLogout}
            style={{
              background: "#ffffff",
              color: green,
              border: "none",
              padding: "8px 14px",
              borderRadius: 8,
              cursor: "pointer",
              fontWeight: 600,
              fontSize: 14,
            }}
          >
            Logout
          </button>
        </header>

        {/* Main content */}
        <main style={{ padding: 18 }}>
          <h3 style={{ color: green, marginBottom: 8 }}>Employee Information</h3>
          <div
            style={{
              display: "grid",
              gridTemplateColumns: "repeat(auto-fit, minmax(220px, 1fr))",
              gap: 10,
              background: "#f9fff9",
              borderRadius: 10,
              padding: 16,
              border: `1px solid ${lightGreen}`,
            }}
          >
            <InfoRow label="Name" value={employee.name} />
            <InfoRow label="Employee ID" value={employee.empld} />
            <InfoRow label="Department" value={employee.department} />
            <InfoRow label="Role" value={employee.role} />
            <InfoRow label="Email" value={employee.email} />
            <InfoRow label="Phone" value={employee.phone} />
            <InfoRow label="Joining Date" value={employee.joiningDate} />
          </div>

          <h3 style={{ color: green, marginTop: 20, marginBottom: 8 }}>
            Quick Summary
          </h3>
          <div
            style={{
              display: "flex",
              flexWrap: "wrap",
              gap: 14,
            }}
          >
            <SummaryCard title="Travel Expenses" value={travelCount} emoji="🚌" />
            <SummaryCard title="Ticket Expenses" value={ticketCount} emoji="🎫" />
          </div>

          {message && (
            <div style={{ marginTop: 12, color: green, fontSize: 13 }}>
              {message}
            </div>
          )}
        </main>
      </div>
    </div>
  );
}

function InfoRow({ label, value }) {
  return (
    <div style={{ fontSize: 14 }}>
      <span style={{ fontWeight: 600, color: "#2e7d32" }}>{label}:</span>{" "}
      <span style={{ color: "#333" }}>{value || "-"}</span>
    </div>
  );
}

function SummaryCard({ title, value, emoji }) {
  return (
    <div
      style={{
        flex: "0 0 160px",
        background: "#e8f5e9",
        borderRadius: 12,
        padding: 14,
        display: "flex",
        flexDirection: "column",
        gap: 6,
      }}
    >
      <div style={{ fontSize: 18 }}>{emoji}</div>
      <div style={{ fontSize: 14, fontWeight: 600, color: "#1b5e20" }}>
        {title}
      </div>
      <div style={{ fontSize: 20, fontWeight: 700, color: "#1b5e20" }}>
        {value}
      </div>
    </div>
  );
}

export default Dashboard;
